+            tmp_entries[new_hash] = key;
+            tmp_entries[new_hash + 1] = value;
+        }
+    }
+
+    aeron_free(map->entries);
+
+    map->entries = tmp_entries;
+    map->entries_length = new_entries_length;
+
+    return 0;
+}
