+/// Extracted from private static method of ReaderWriterQueue
+size_t ceilToPow2(size_t x)
+{
+	// From http://graphics.stanford.edu/~seander/bithacks.html#RoundUpPowerOf2
+	--x;
+	x |= x >> 1;
+	x |= x >> 2;
+	x |= x >> 4;
+	for (size_t i = 1; i < sizeof(size_t); i <<= 1) {
+		x |= x >> (i << 3);
+	}
+	++x;
+	return x;
+}
