    EXPECT_EQ(AERON_ACTION_ABORT, handle_fragment(handler, fragmentLength));
    EXPECT_EQ(AERON_ACTION_ABORT, handle_fragment(handler, fragmentLength));

    EXPECT_EQ(2, callCount);
}

